ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?amenities a :Amenity .
    ?frequentflyerlounges a :VIPLounges .
    ?frequentflyerlounges p:hasAmenities ?amenities .
    ?frequentflyerlounges p:capacity ?capacity .
    ?amenities p:description ?description_f .
    FILTER(STR(?description_f) = "Power outlets at every seat")
    BIND(?capacity AS ?o0)
  }
  UNION
  {
    ?amenities a :Amenity .
    ?viplounges a :VIPLounges .
    ?viplounges p:hasAmenities ?amenities .
    ?viplounges p:capacity ?capacity .
    ?amenities p:description ?description_f .
    FILTER(STR(?description_f) = "Power outlets at every seat")
    BIND(?capacity AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?amenities a :Amenity .
    ?frequentflyerlounges a :VIPLounges .
    ?frequentflyerlounges p:hasAmenities ?amenities .
    ?frequentflyerlounges p:capacity ?capacity .
    BIND(?capacity AS ?o0)
  }
  UNION
  {
    ?amenities a :Amenity .
    ?viplounges a :VIPLounges .
    ?viplounges p:hasAmenities ?amenities .
    ?viplounges p:capacity ?capacity .
    ?amenities p:description ?description_f .
    FILTER(STR(?description_f) = "Power outlets at every seat")
    BIND(?capacity AS ?o0)
  }
} }
}
